import React, { useState, useEffect } from 'react';
import axios from 'axios';
import * as XLSX from 'xlsx';
import Sidebar from '../components/Sidebar';
import './Pages.css';

const CustomerHistory = () => {
  const [language, setLanguage] = useState('en');
  const [customers, setCustomers] = useState([]);
  const [selectedCustomer, setSelectedCustomer] = useState('');
  const [bills, setBills] = useState([]);
  const [loading, setLoading] = useState(false);

  // ✅ NEW STATES (SEARCH UPGRADE)
  const [searchName, setSearchName] = useState('');
  const [filteredCustomers, setFilteredCustomers] = useState([]);
  const [showSuggestions, setShowSuggestions] = useState(false);

  const translations = {
    en: { 
      customerHistory: 'Customer History', 
      selectCustomer: 'Select Customer', 
      bills: 'Bills', 
      noData: 'No data available', 
      billNumber: 'Bill Number',
      date: 'Date', 
      items: 'Items',
      subtotal: 'Subtotal',
      paidAmount: 'Paid Amount',
      pendingAmount: 'Pending Amount',
      grandTotal: 'Grand Total',
      amount: 'Amount', 
      status: 'Status',
      downloadExcel: 'Download Excel',
      village: 'Village'
    },
    te: { 
      customerHistory: 'కస్టమర్ హిస్టరీ', 
      selectCustomer: 'కస్టమర్‌ను ఎంచుకోండి', 
      bills: 'బిల్లులు', 
      noData: 'డేటా లేదు', 
      billNumber: 'బిల్ నంబర్',
      date: 'తేదీ', 
      items: 'సరుకులు',
      subtotal: 'ఉపమొత్తం',
      paidAmount: 'చెల్లిన మొత్తం',
      pendingAmount: 'బకాయి మొత్తం',
      grandTotal: 'మొత్తం',
      amount: 'మొత్తం', 
      status: 'స్థితి',
      downloadExcel: 'ఎక్సెల్ డౌన్లోడ్ చేయండి',
      village: 'గ్రామం'
    },
    hi: { 
      customerHistory: 'ग्राहक इतिहास', 
      selectCustomer: 'ग्राहक चुनें', 
      bills: 'बिल', 
      noData: 'कोई डेटा नहीं', 
      billNumber: 'बिल नंबर',
      date: 'तारीख', 
      items: 'वस्तुएं',
      subtotal: 'उप-कुल',
      paidAmount: 'भुगतान की गई राशि',
      pendingAmount: 'बकाया राशि',
      grandTotal: 'कुल राशि',
      amount: 'राशि', 
      status: 'स्थिति',
      downloadExcel: 'एक्सेल डाउनलोड करें',
      village: 'गाँव'
    }
  };

  const t = translations[language] || translations.en;

  useEffect(() => {
    fetchCustomers();
  }, []);

  const fetchCustomers = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get('http://localhost:5000/api/accounts/customers', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setCustomers(response.data.accounts || []);
    } catch (err) {
      console.error('Error:', err);
    }
  };

  const handleSelectCustomer = async (customerId) => {
    setSelectedCustomer(customerId);
    setLoading(true);
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get(`http://localhost:5000/api/bills/customer/${customerId}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setBills(response.data.bills || []);
    } catch (err) {
      console.error('Error:', err);
    } finally {
      setLoading(false);
    }
  };

  // ✅ LIVE SEARCH
  const handleSearchChange = (value) => {
    setSearchName(value);

    if (!value.trim()) {
      setFilteredCustomers([]);
      setShowSuggestions(false);
      return;
    }

    const filtered = customers.filter(c =>
      c.customerName.toLowerCase().includes(value.toLowerCase())
    );

    setFilteredCustomers(filtered);
    setShowSuggestions(true);
  };

  // ✅ SELECT FROM SUGGESTION
  const handleSelectSuggestion = async (customer) => {
    setSearchName(customer.customerName);
    setShowSuggestions(false);
    setSelectedCustomer(customer._id);

    setLoading(true);
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get(
        `http://localhost:5000/api/bills/customer/${customer._id}`,
        {
          headers: { Authorization: `Bearer ${token}` }
        }
      );
      setBills(response.data.bills || []);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const downloadExcel = () => {
    if (bills.length === 0) return;

    const exportData = bills.map(bill => ({
      [t.billNumber]: bill.billNumber || 'N/A',
      [t.date]: new Date(bill.createdAt).toLocaleDateString(),
      [t.village]: bill.village || 'N/A',
      [t.items]: bill.items?.length || 0,
      [t.subtotal]: bill.subtotal?.toFixed(2) || '0.00',
      [t.paidAmount]: bill.paidAmount?.toFixed(2) || '0.00',
      [t.pendingAmount]: bill.pendingAmount?.toFixed(2) || '0.00',
      [t.grandTotal]: bill.grandTotal?.toFixed(2) || '0.00',
      [t.status]: bill.status || 'N/A'
    }));

    const ws = XLSX.utils.json_to_sheet(exportData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'Bills');

    const customer = customers.find(c => c._id === selectedCustomer);
    const fileName = `Bill_History_${customer?.customerName || 'Customer'}.xlsx`;

    XLSX.writeFile(wb, fileName);
  };

  return (
    <div className="dashboard-layout">
      <Sidebar language={language} />
      <div className="main-content">
        <div className="top-bar">
          <h1>{t.customerHistory}</h1>
        </div>

        <div className="page-card">

          {/* ✅ SEARCH BOX */}
          <div className="form-group" style={{ position: 'relative' }}>
            <label>Search Customer</label>
            <input
              type="text"
              placeholder="Type name..."
              value={searchName}
              onChange={(e) => handleSearchChange(e.target.value)}
              style={{ padding: '10px', width: '100%' }}
            />

            {showSuggestions && filteredCustomers.length > 0 && (
              <div style={{
                position: 'absolute',
                background: '#fff',
                border: '1px solid #ddd',
                width: '100%',
                maxHeight: '200px',
                overflowY: 'auto',
                zIndex: 1000
              }}>
                {filteredCustomers.map(c => (
                  <div
                    key={c._id}
                    onClick={() => handleSelectSuggestion(c)}
                    style={{ padding: '10px', cursor: 'pointer' }}
                  >
                    <strong>{c.customerName}</strong><br />
                    <small>{c.phone} | {c.village}</small>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* OLD DROPDOWN (kept safe) */}
          <div className="form-group">
            <label>{t.selectCustomer}</label>
            <select value={selectedCustomer} onChange={(e) => handleSelectCustomer(e.target.value)}>
              <option value="">-- {t.selectCustomer} --</option>
              {customers.map(c => <option key={c._id} value={c._id}>{c.customerName}</option>)}
            </select>
          </div>

          {selectedCustomer && (
            <div className="bills-table-container">
              <h2>{t.bills}</h2>

              {bills.length === 0 ? (
                <p>{t.noData}</p>
              ) : (
                <table className="bills-table">
                  <thead>
                    <tr>
                      <th>{t.billNumber}</th>
                      <th>{t.date}</th>
                      <th>{t.village}</th>
                      <th>{t.items}</th>
                      <th>{t.subtotal}</th>
                      <th>{t.paidAmount}</th>
                      <th>{t.pendingAmount}</th>
                      <th>{t.grandTotal}</th>
                      <th>{t.status}</th>
                    </tr>
                  </thead>
                  <tbody>
                    {bills.map((bill) => (
                      <tr key={bill._id}>
                        <td>{bill.billNumber}</td>
                        <td>{new Date(bill.createdAt).toLocaleDateString()}</td>
                        <td>{bill.village}</td>
                        <td>{bill.items?.length}</td>
                        <td>₹ {bill.subtotal}</td>
                        <td>₹ {bill.paidAmount}</td>
                        <td>₹ {bill.pendingAmount}</td>
                        <td>₹ {bill.grandTotal}</td>
                        <td>{bill.status}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default CustomerHistory;
